def proposed_select_child(node: MCTSNode, context: Dict[str, Any]) -> MCTSNode:
    c = float(context.get("subtree_exploration_constant", 0.9))
    return uct_select_child(node, exploration_constant=c)


def proposed_rollout(
    problem: SearchProblem,
    state: State,
    rng: np.random.Generator,
    context: Dict[str, Any],
) -> float:
    current = state
    greedy_prob = float(context.get("rollout_greedy_prob", 0.85))
    while not problem.is_terminal(current):
        actions = problem.actions(current)
        if not actions:
            break
        use_greedy = rng.random() < greedy_prob
        action = problem.greedy_action(current) if use_greedy else None
        if action is None:
            action = actions[int(rng.integers(0, len(actions)))]
        current = problem.step(current, action)
    return problem.evaluate_state(current)


def proposed_backup(node: MCTSNode, value: float, context: Dict[str, Any]) -> None:
    _ = context
    backup_value(node, value)


def rs_allocate_round_sizes(total_budget: int, n_arms: int) -> List[int]:
    if total_budget <= 0 or n_arms <= 0:
        return []
    survivors = n_arms
    remaining = total_budget
    rounds: List[int] = []
    while survivors > 1 and remaining > 0:
        n_rounds_left = int(math.ceil(math.log2(survivors)))
        probes = max(1, remaining // max(survivors * n_rounds_left, 1))
        rounds.append(probes)
        remaining -= probes * survivors
        survivors = max(1, (survivors + 1) // 2)
    if remaining > 0:
        rounds.append(max(1, remaining))
    return rounds


def rs_shallow_probe(
    problem: SearchProblem,
    root_state: State,
    root_action: Action,
    rng: np.random.Generator,
    context: Dict[str, Any],
    rollout_fn=None,
) -> float:
    if rollout_fn is None:
        rollout_fn = proposed_rollout

    state = problem.step(root_state, root_action)
    if problem.is_terminal(state):
        return problem.evaluate_state(state)

    depth_limit = int(context.get("subtree_depth_limit", 3))
    root = MCTSNode(
        state=state,
        parent=None,
        action=root_action,
        untried_actions=list(problem.actions(state)),
    )

    for _ in range(depth_limit):
        node = root
        depth = 0
        while (
            depth < depth_limit
            and not problem.is_terminal(node.state)
            and not node.untried_actions
            and node.children
        ):
            node = proposed_select_child(node, context)
            depth += 1

        if (
            depth < depth_limit
            and not problem.is_terminal(node.state)
            and node.untried_actions
        ):
            idx = int(rng.integers(0, len(node.untried_actions)))
            action = node.untried_actions.pop(idx)
            next_state = problem.step(node.state, action)
            child = MCTSNode(
                state=next_state,
                parent=node,
                action=action,
                untried_actions=list(problem.actions(next_state)),
            )
            node.children[action] = child
            node = child

        value = rollout_fn(problem, node.state, rng, context)
        proposed_backup(node, value, context)

    return (
        root.mean_value if root.visits > 0 else rollout_fn(problem, state, rng, context)
    )


def proposed_random_rollout_ablation(
    problem: SearchProblem,
    state: State,
    rng: np.random.Generator,
    context: Dict[str, Any],
) -> float:
    _ = context
    return rollout_random(problem, state, rng)


def proposed_mcts_choose_action_core(
    problem: SearchProblem,
    root_state: State,
    per_decision_budget: int,
    rng: np.random.Generator,
    rollout_fn,
) -> Optional[Action]:
    root_actions = list(problem.actions(root_state))
    if not root_actions:
        return None
    if len(root_actions) == 1:
        return root_actions[0]

    context: Dict[str, Any] = {
        "problem_name": problem.name,
        "per_decision_budget": per_decision_budget,
        "subtree_exploration_constant": 0.9,
        "rollout_greedy_prob": 0.85,
        "subtree_depth_limit": (
            2 if per_decision_budget <= 16 else (3 if per_decision_budget <= 64 else 4)
        ),
    }

    active = list(root_actions)
    stats: Dict[Action, Dict[str, float]] = {
        a: {"n": 0.0, "sum": 0.0} for a in root_actions
    }
    round_sizes = rs_allocate_round_sizes(per_decision_budget, len(root_actions))

    budget_used = 0
    for probes_per_arm in round_sizes:
        if not active or budget_used >= per_decision_budget:
            break
        affordable = max(1, (per_decision_budget - budget_used) // max(len(active), 1))
        probes_this_round = min(probes_per_arm, affordable)
        if probes_this_round <= 0:
            break

        for action in active:
            for _ in range(probes_this_round):
                value = rs_shallow_probe(
                    problem, root_state, action, rng, context, rollout_fn=rollout_fn
                )
                stats[action]["n"] += 1.0
                stats[action]["sum"] += float(value)
                budget_used += 1
                if budget_used >= per_decision_budget:
                    break
            if budget_used >= per_decision_budget:
                break

        if len(active) <= 1 or budget_used >= per_decision_budget:
            continue

        scored: List[Tuple[float, float, Action]] = []
        for action in active:
            n = stats[action]["n"]
            mean = stats[action]["sum"] / max(n, 1.0)
            radius = math.sqrt(2.0 * math.log(max(budget_used, 2)) / max(n, 1.0))
            lcb = mean - radius
            scored.append((lcb, mean, action))

        scored.sort(reverse=True)
        keep = max(1, (len(active) + 1) // 2)
        active = [a for _, _, a in scored[:keep]]

    best_action = None
    best_key = (-float("inf"), -float("inf"))
    for action in root_actions:
        n = stats[action]["n"]
        if n <= 0:
            continue
        mean = stats[action]["sum"] / n
        key = (mean, n)
        if key > best_key:
            best_key = key
            best_action = action

    if best_action is not None:
        return best_action
    return root_actions[0]


