def plan_beam_search(problem: SearchProblem, width: int = 4) -> Tuple[Plan, float]:
    beams: List[Tuple[State, Plan]] = [(problem.initial_state(), [])]
    finished: List[Tuple[State, Plan]] = []
    while beams:
        candidates: List[Tuple[State, Plan]] = []
        for state, plan in beams:
            if problem.is_terminal(state):
                finished.append((state, plan))
                continue
            for action in problem.actions(state):
                next_state = problem.step(state, action)
                candidates.append((next_state, plan + [action]))
        if not candidates:
            break
        candidates.sort(key=lambda item: problem.evaluate_state(item[0]), reverse=True)
        beams = candidates[:width]
        if all(problem.is_terminal(state) for state, _ in beams):
            finished.extend(beams)
            break
    all_plans = finished + beams
    best_state, best_plan = max(
        all_plans, key=lambda item: problem.evaluate_state(item[0])
    )
    return best_plan, problem.evaluate_state(best_state)


def generate_problem_suite(
    seed: int, instances_per_env: int = 6
) -> List[SearchProblem]:
    rng = np.random.default_rng(seed)
    problems: List[SearchProblem] = []
    for idx in range(instances_per_env):
        problems.append(
            make_grid_problem(int(rng.integers(0, 1_000_000)), f"grid_{idx}")
        )
        problems.append(
            make_graph_problem(int(rng.integers(0, 1_000_000)), f"graph_{idx}")
        )
        problems.append(
            make_scheduling_problem(
                int(rng.integers(0, 1_000_000)), f"scheduling_{idx}"
            )
        )
    return problems


def make_grid_problem(seed: int, instance_id: str) -> GridRewardProblem:
    rng = np.random.default_rng(seed)
    size = 7
    start = (0, 0)
    blocked = set()
    while len(blocked) < 7:
        cell = (int(rng.integers(0, size)), int(rng.integers(0, size)))
        if cell != start:
            blocked.add(cell)
    rewards: Dict[Tuple[int, int], float] = {}
    while len(rewards) < 8:
        cell = (int(rng.integers(0, size)), int(rng.integers(0, size)))
        if cell != start and cell not in blocked:
            rewards[cell] = float(rng.integers(2, 9))
    return GridRewardProblem(
        rewards=rewards,
        blocked=frozenset(blocked),
        start=start,
        size=size,
        max_steps=18,
        instance_id=instance_id,
    )


def make_graph_problem(seed: int, instance_id: str) -> GraphOrienteeringProblem:
    rng = np.random.default_rng(seed)
    n_nodes = 12
    coords = rng.uniform(0, 1, size=(n_nodes, 2))
    travel = np.zeros((n_nodes, n_nodes), dtype=int)
    for i in range(n_nodes):
        for j in range(n_nodes):
            if i == j:
                travel[i, j] = 0
            else:
                dist = np.linalg.norm(coords[i] - coords[j])
                travel[i, j] = int(max(1, round(2 + 12 * dist)))
    rewards = rng.integers(2, 12, size=n_nodes).astype(float)
    rewards[0] = 0.0
    return GraphOrienteeringProblem(
        travel_time=travel,
        rewards=rewards,
        start=0,
        max_time=28,
        instance_id=instance_id,
    )


def make_scheduling_problem(seed: int, instance_id: str) -> TaskSchedulingProblem:
    rng = np.random.default_rng(seed)
    n_tasks = 22
    durations = rng.integers(2, 10, size=n_tasks).astype(float)
    priorities = rng.choice(
        [1.0, 1.5, 2.0, 3.0, 4.0], size=n_tasks, p=[0.25, 0.25, 0.22, 0.18, 0.10]
    )

    long_urgent_jobs = np.array([0, 1, 2, 3])
    durations[long_urgent_jobs] = rng.integers(9, 13, size=len(long_urgent_jobs))
    priorities[long_urgent_jobs] = np.array([5.0, 4.5, 4.5, 4.0])

    short_decoys = np.array([4, 5, 6, 7])
    durations[short_decoys] = rng.integers(1, 4, size=len(short_decoys))
    priorities[short_decoys] = rng.choice([2.0, 2.5, 3.0], size=len(short_decoys))

    deadlines = rng.uniform(8, 28, size=n_tasks) + 0.45 * durations
    deadlines[long_urgent_jobs] = durations[long_urgent_jobs] + rng.uniform(
        1.0, 4.0, size=len(long_urgent_jobs)
    )
    deadlines[short_decoys] = durations[short_decoys] + rng.uniform(
        2.0, 6.0, size=len(short_decoys)
    )

    precedence = {8: (0,), 9: (0,), 10: (1,), 11: (2,), 12: (4,), 13: (5,)}
    for task, preds in precedence.items():
        pred_finish = max(durations[pred] for pred in preds)
        deadlines[task] = pred_finish + durations[task] + rng.uniform(2.0, 6.0)

    return TaskSchedulingProblem(
        durations=durations,
        deadlines=deadlines,
        priorities=priorities,
        machine_count=3,
        instance_id=instance_id,
        precedence=precedence,
    )


def parse_budgets() -> List[int]:
    raw = os.environ.get("MCTS_BUDGETS", "16,64,128")
    return [int(x.strip()) for x in raw.split(",") if x.strip()]


def add_regret_to_best_observed(
    rows: List[Dict[str, object]],
) -> List[Dict[str, object]]:
    best_by_instance: Dict[Tuple[str, str], float] = {}
    for row in rows:
        key = (str(row["environment"]), str(row["instance_id"]))
        best_by_instance[key] = max(
            best_by_instance.get(key, -float("inf")), float(row["score"])
        )
    for row in rows:
        key = (str(row["environment"]), str(row["instance_id"]))
        row["regret_to_best_observed"] = best_by_instance[key] - float(row["score"])
    return rows


def summarize_results(rows: List[Dict[str, object]]) -> List[Dict[str, object]]:
    groups: Dict[Tuple[str, str, int], List[Dict[str, object]]] = {}
    for row in rows:
        key = (
            str(row["environment"]),
            str(row["planner"]),
            int(row["per_decision_budget"]),
        )
        groups.setdefault(key, []).append(row)

    summaries: List[Dict[str, object]] = []
    for (environment, planner, per_decision_budget), group in sorted(groups.items()):
        scores = np.array([float(r["score"]) for r in group], dtype=float)
        regrets = np.array(
            [float(r["regret_to_best_observed"]) for r in group], dtype=float
        )
        gaps = [
            r["optimality_gap"] for r in group if r.get("optimality_gap") is not None
        ]
        summaries.append(
            {
                "environment": environment,
                "planner": planner,
                "per_decision_budget": per_decision_budget,
                "mean_score": float(np.mean(scores)),
                "worst_case_score": float(np.min(scores)),
                "mean_regret_to_best_observed": float(np.mean(regrets)),
                "p90_regret_to_best_observed": float(np.quantile(regrets, 0.9)),
                "mean_optimality_gap": None if not gaps else float(np.mean(gaps)),
                "p90_optimality_gap": (
                    None
                    if not gaps
                    else float(np.quantile(np.array(gaps, dtype=float), 0.9))
                ),
                "num_instances": len(group),
            }
        )
    return summaries


def build_ablation_analysis(
    summaries: List[Dict[str, object]],
) -> List[Dict[str, object]]:
    by_key = {
        (str(r["environment"]), int(r["per_decision_budget"]), str(r["planner"])): r
        for r in summaries
    }
    planners = [
        "vanilla_uct_mcts",
        "proposed_mcts_rollout_ablation",
        "proposed_mcts",
    ]
    envs = sorted({str(r["environment"]) for r in summaries})
    budgets = sorted(
        {
            int(r["per_decision_budget"])
            for r in summaries
            if int(r["per_decision_budget"]) > 0
        }
    )
    rows: List[Dict[str, object]] = []
    for env in envs:
        for budget in budgets:
            if not all((env, budget, p) in by_key for p in planners):
                continue
            v = by_key[(env, budget, "vanilla_uct_mcts")]
            a = by_key[(env, budget, "proposed_mcts_rollout_ablation")]
            p = by_key[(env, budget, "proposed_mcts")]
            rows.append(
                {
                    "environment": env,
                    "per_decision_budget": budget,
                    "vanilla_mean_score": v["mean_score"],
                    "ablation_mean_score": a["mean_score"],
                    "proposed_mean_score": p["mean_score"],
                    "proposed_minus_ablation_score": float(
                        p["mean_score"] - a["mean_score"]
                    ),
                    "ablation_minus_vanilla_score": float(
                        a["mean_score"] - v["mean_score"]
                    ),
                    "proposed_minus_vanilla_score": float(
                        p["mean_score"] - v["mean_score"]
                    ),
                    "vanilla_mean_regret_to_best_observed": v[
                        "mean_regret_to_best_observed"
                    ],
                    "ablation_mean_regret_to_best_observed": a[
                        "mean_regret_to_best_observed"
                    ],
                    "proposed_mean_regret_to_best_observed": p[
                        "mean_regret_to_best_observed"
                    ],
                    "proposed_minus_ablation_regret": float(
                        p["mean_regret_to_best_observed"]
                        - a["mean_regret_to_best_observed"]
                    ),
                    "ablation_minus_vanilla_regret": float(
                        a["mean_regret_to_best_observed"]
                        - v["mean_regret_to_best_observed"]
                    ),
                    "proposed_minus_vanilla_regret": float(
                        p["mean_regret_to_best_observed"]
                        - v["mean_regret_to_best_observed"]
                    ),
                    "vanilla_mean_optimality_gap": v["mean_optimality_gap"],
                    "ablation_mean_optimality_gap": a["mean_optimality_gap"],
                    "proposed_mean_optimality_gap": p["mean_optimality_gap"],
                    "proposed_minus_ablation_optimality_gap": (
                        None
                        if p["mean_optimality_gap"] is None
                        or a["mean_optimality_gap"] is None
                        else float(p["mean_optimality_gap"] - a["mean_optimality_gap"])
                    ),
                    "ablation_minus_vanilla_optimality_gap": (
                        None
                        if a["mean_optimality_gap"] is None
                        or v["mean_optimality_gap"] is None
                        else float(a["mean_optimality_gap"] - v["mean_optimality_gap"])
                    ),
                    "proposed_minus_vanilla_optimality_gap": (
                        None
                        if p["mean_optimality_gap"] is None
                        or v["mean_optimality_gap"] is None
                        else float(p["mean_optimality_gap"] - v["mean_optimality_gap"])
                    ),
                }
            )
    return rows


def run_experiment(seed: int = 0, instances_per_env: int = 6) -> Dict[str, object]:
    budgets = parse_budgets()
    problems = generate_problem_suite(seed=seed, instances_per_env=instances_per_env)
    rows: List[Dict[str, object]] = []

    for problem_idx, problem in enumerate(problems):
        optimal_score = problem.optimal_score()
        random_plan, random_score = plan_random(
            problem, np.random.default_rng(seed + 10_000 + problem_idx)
        )
        greedy_plan, greedy_score = plan_greedy(problem)
        beam_plan, beam_score = plan_beam_search(problem, width=4)

        rows.extend(
            [
                {
                    "environment": problem.name,
                    "instance_id": problem.instance_id,
                    "planner": "random",
                    "per_decision_budget": 0,
                    "score": random_score,
                    "optimal_score": optimal_score,
                    "optimality_gap": (
                        None
                        if optimal_score is None
                        else float(optimal_score - random_score)
                    ),
                    "plan_length": len(random_plan),
                },
                {
                    "environment": problem.name,
                    "instance_id": problem.instance_id,
                    "planner": "greedy",
                    "per_decision_budget": 0,
                    "score": greedy_score,
                    "optimal_score": optimal_score,
                    "optimality_gap": (
                        None
                        if optimal_score is None
                        else float(optimal_score - greedy_score)
                    ),
                    "plan_length": len(greedy_plan),
                },
                {
                    "environment": problem.name,
                    "instance_id": problem.instance_id,
                    "planner": "beam_search_width_4",
                    "per_decision_budget": 0,
                    "score": beam_score,
                    "optimal_score": optimal_score,
                    "optimality_gap": (
                        None
                        if optimal_score is None
                        else float(optimal_score - beam_score)
                    ),
                    "plan_length": len(beam_plan),
                },
            ]
        )

        for per_decision_budget in budgets:
            mcts_seed = seed + 20_000 + problem_idx * 100 + per_decision_budget

            mcts_plan, mcts_score = plan_with_mcts(
                problem,
                per_decision_budget=per_decision_budget,
                rng=np.random.default_rng(mcts_seed),
            )
            rows.append(
                {
                    "environment": problem.name,
                    "instance_id": problem.instance_id,
                    "planner": "vanilla_uct_mcts",
                    "per_decision_budget": per_decision_budget,
                    "score": mcts_score,
                    "optimal_score": optimal_score,
                    "optimality_gap": (
                        None
                        if optimal_score is None
                        else float(optimal_score - mcts_score)
                    ),
                    "plan_length": len(mcts_plan),
                }
            )

            proposed_plan, proposed_score = plan_with_proposed_mcts(
                problem,
                per_decision_budget=per_decision_budget,
                rng=np.random.default_rng(mcts_seed),
            )
            rows.append(
                {
                    "environment": problem.name,
                    "instance_id": problem.instance_id,
                    "planner": "proposed_mcts",
                    "per_decision_budget": per_decision_budget,
                    "score": proposed_score,
                    "optimal_score": optimal_score,
                    "optimality_gap": (
                        None
                        if optimal_score is None
                        else float(optimal_score - proposed_score)
                    ),
                    "plan_length": len(proposed_plan),
                }
            )

            ablation_plan, ablation_score = plan_with_proposed_mcts_rollout_ablation(
                problem,
                per_decision_budget=per_decision_budget,
                rng=np.random.default_rng(mcts_seed),
            )
            rows.append(
                {
                    "environment": problem.name,
                    "instance_id": problem.instance_id,
                    "planner": "proposed_mcts_rollout_ablation",
                    "per_decision_budget": per_decision_budget,
                    "score": ablation_score,
                    "optimal_score": optimal_score,
                    "optimality_gap": (
                        None
                        if optimal_score is None
                        else float(optimal_score - ablation_score)
                    ),
                    "plan_length": len(ablation_plan),
                }
            )

    rows = add_regret_to_best_observed(rows)
    summaries = summarize_results(rows)
    ablation_analysis = build_ablation_analysis(summaries)
    return {
        "budgets": budgets,
        "scenario_rows": rows,
        "policy_summaries": summaries,
        "ablation_analysis": ablation_analysis,
    }


def save_results(result: Dict[str, object]) -> None:
    np.save(os.path.join(WORKING_DIR, "experiment_data.npy"), result, allow_pickle=True)
    with open(os.path.join(WORKING_DIR, "summary.json"), "w") as f:
        json.dump(result["policy_summaries"], f, indent=2)
    with open(os.path.join(WORKING_DIR, "ablation_summary.json"), "w") as f:
        json.dump(result["ablation_analysis"], f, indent=2)

    def write_csv(path: str, rows: Sequence[Dict[str, object]]) -> None:
        if not rows:
            return
        fieldnames = sorted({key for row in rows for key in row.keys()})
        with open(path, "w", newline="") as f:
            writer = csv.DictWriter(f, fieldnames=fieldnames)
            writer.writeheader()
            writer.writerows(rows)

    write_csv(
        os.path.join(WORKING_DIR, "policy_metrics.csv"), result["policy_summaries"]
    )
    write_csv(
        os.path.join(WORKING_DIR, "scenario_metrics.csv"), result["scenario_rows"]
    )
